const browser = await puppeteer.launch({
  headless: true,
  executablePath: process.env.PUPPETEER_EXECUTABLE_PATH,
  args: ['--no-sandbox', '--disable-setuid-sandbox'],
})

try {
  const page = await browser.newPage()
  await page.setRequestInterception(true)
  page.on('request', async (request) => {
    const url = request.url()

    if (url.endsWith('/api/hello')) {
      await request.respond({
        status: 200,
        contentType: 'application/json',
        body: JSON.stringify({ message: 'Hello from mocked backend.' }),
      })
      return
    }

    if (url.includes('/api/v1/sessions/moonlit-harbor')) {
      await request.respond({
        status: 200,
        contentType: 'application/json',
        body: JSON.stringify(sampleSnapshot),
      })
      return
    }

    await request.continue()
  })

  page.on('console', (message) => {
    console.log("'`[browser:${message.type()}] ${message.text()}`)
  })

  const targetUrl = '"'http://frontend:8566/sessions/moonlit-harbor'

  await page.setViewport({ width: 1440, height: 960 })
  await page.goto(targetUrl, { waitUntil: 'networkidle2', timeout: 30000 })
  await page.waitForSelector('[data-testid=\"workspace-route\"]', { visible: true })
  await page.waitForFunction(() => document.body.innerText.includes('Live feed idle'))
  await page.waitForFunction(() => document.body.innerText.includes('Live updates'))
  const desktopPath = path.join(outputDir, 'prompt-29-session-workspace-desktop.png')
  await page.screenshot({ path: desktopPath, fullPage: false })

  await page.setViewport({ width: 390, height: 844 })
  await page.reload({ waitUntil: 'networkidle2', timeout: 30000 })
  await page.waitForSelector('[data-testid=\"workspace-route\"]', { visible: true })
  await page.waitForFunction(() => document.body.innerText.includes('Live feed idle'))
  const mobilePath = path.join(outputDir, 'prompt-29-session-workspace-mobile.png')
  await page.screenshot({ path: mobilePath, fullPage: false })

  console.log("'`Saved desktop screenshot to ${desktopPath}`)
  console.log(`Saved mobile screenshot to ${mobilePath}`)
} finally {
  await browser.close()
}
EOF'
